  { date: 'Sat, 14 Mar 2026 21:00:26 +0000', from: 'Codecademy <learn@itr.mail.codecademy.com>', subject: 'LAST CHANCE: Save 20% on our Data Structures and Algorithms bootcamp' },
  { date: 'Sat, 14 Mar 2026 15:19:07 +0000', from: 'Stack Overflow <do-not-reply@hello.stackoverflow.email>', subject: 'Start here. Ask AI Assist!' },
  { date: 'Fri, 13 Mar 2026 15:19:03 +0000', from: 'Stack Overflow <do-not-reply@hello.stackoverflow.email>', subject: 'Welcome to Stack Overflow' },
  { date: 'Tue, 10 Mar 2026 23:01:37 +0000', from: 'Mermaid <hello@mermaid.ai>', subject: 'The Mermaid community is officially open' },
  { date: 'Wed, 11 Mar 2026 13:39:51 +0000', from: 'Qdrant Cloud <no-reply@qdrant.io>', subject: 'Updates to our Data Processing and Service Level Agreement' },
  { date: 'Wed, 11 Mar 2026 16:56:19 -0700', from: 'Kaggle <no-reply@kaggle.com>', subject: 'Competition Launch: BirdCLEF+ 2026' },
  { date: 'Thu, 12 Mar 2026 15:30:14 +0000', from: 'Archie Chrisanthou <archdrawsalot@creators.gumroad.com>', subject: 'NEW Wallpapers!' },
  { date: 'Fri, 13 Mar 2026 08:56:13 GMT', from: 'Google <no-reply@accounts.google.com>', subject: 'Security alert' },
  { date: 'Tue, 10 Mar 2026 22:08:02 +0000', from: '\"Amazon.com\" <store-news@amazon.com>', subject: 'So many choices, all on Amazon' },
  { date: 'Sun, 15 Mar 2026 13:52:35 GMT', from: 'Google <no-reply@accounts.google.com>', subject: 'Security alert' },
  { date: 'Thu, 12 Mar 2026 03:38:00 GMT', from: 'Google <no-reply@accounts.google.com>', subject: 'Security alert' },
];

console.log('=== TOTAL COUNT ===');
console.log(messages.length);

// Extract domain from email
function extractDomain(from) {
  const match = from.match(/<[^>]*@([^>]+)>/) || from.match(/@([^\s>]+)/);
  return match ? match[1].toLowerCase() : 'unknown';
}

// Domain grouping
const domainCounts = {};
messages.forEach(m => {
  const domain = extractDomain(m.from);
  domainCounts[domain] = (domainCounts[domain] || 0) + 1;
});

console.log('\n=== DOMAIN COUNTS ===');
const sorted = Object.entries(domainCounts).sort((a, b) => b[1] - a[1]);
sorted.forEach(([d, c]) => console.log(d + ': ' + c));

console.log('\n=== TOP 3 ===');
sorted.slice(0, 3).forEach(([d, c]) => console.log(d + ': ' + c));

// Urgent flag
const urgent = messages.filter(m => {
  const s = m.subject.toLowerCase();
  return s.includes('urgent') || s.includes('action required');
});
console.log('\n=== URGENT/ACTION REQUIRED ===');
console.log('Count:', urgent.length);
urgent.forEach(m => console.log(' -', m.subject, '|', m.from));

// Oldest email
const parsed = messages.map(m => ({ ...m, ts: new Date(m.date).getTime() }));
const oldest = parsed.sort((a, b) => a.ts - b.ts)[0];
console.log('\n=== OLDEST ===');
console.log('Date:', oldest.date);
console.log('Subject:', oldest.subject);
console.log('From:', oldest.from);
"

